export type UploadMode = 'presigned' | 'multipart';

export interface UploadRequestInput {
  filename: string;
  contentType?: string;
  size?: number;
  mode?: UploadMode;
}

export interface PresignedUploadResponse {
  mode: 'presigned';
  uploadUrl: string;
  method?: 'PUT' | 'POST';
  headers?: Record<string, string>;
  fileUrl?: string;
  key?: string;
}

export interface MultipartUploadResponse {
  mode: 'multipart';
  uploadUrl: string;
  method?: 'POST' | 'PUT';
  headers?: Record<string, string>;
  fields?: Record<string, string>;
  fileUrl?: string;
  key?: string;
}

export type UploadRequestResponse = PresignedUploadResponse | MultipartUploadResponse;

export interface UploadResult {
  fileUrl?: string;
  key?: string;
  response: Response;
}

export interface UploadProgressEvent {
  loaded: number;
  total?: number;
  percent?: number;
}

export type UploadProgressHandler = (progress: UploadProgressEvent) => void;

export interface TrackUploadProgressOptions {
  onProgress?: UploadProgressHandler;
}

function isFormData(value: unknown): value is FormData {
  return typeof FormData !== 'undefined' && value instanceof FormData;
}

async function requestJson<T>(input: RequestInfo | URL, init?: RequestInit): Promise<T> {
  const response = await fetch(input, {
    headers: {
      'Content-Type': 'application/json',
      ...(init?.headers ?? {}),
    },
    ...init,
  });

  if (!response.ok) {
    const message = await response.text().catch(() => '');
    throw new Error(message || `Request failed with status ${response.status}`);
  }

  if (response.status === 204) {
    return undefined as T;
  }

  return (await response.json()) as T;
}

export async function requestUpload(input: UploadRequestInput): Promise<UploadRequestResponse> {
  return requestJson<UploadRequestResponse>('/api/uploads/request', {
    method: 'POST',
    body: JSON.stringify(input),
  });
}

function parseUploadResponseMetadata(response: Response): Pick<UploadResult, 'fileUrl' | 'key'> {
  const fileUrl = response.headers.get('x-file-url') ?? response.headers.get('location') ?? undefined;
  const key = response.headers.get('x-file-key') ?? undefined;
  return { fileUrl, key };
}

export function trackUploadProgress(options: TrackUploadProgressOptions = {}) {
  const xhr = new XMLHttpRequest();

  if (options.onProgress) {
    xhr.upload.onprogress = (event: ProgressEvent<EventTarget>) => {
      const total = event.lengthComputable ? event.total : undefined;
      options.onProgress({
        loaded: event.loaded,
        total,
        percent: total ? Math.round((event.loaded / total) * 100) : undefined,
      });
    };
  }

  return xhr;
}

async function sendMultipartUpload(
  response: MultipartUploadResponse,
  file: File | Blob,
  options: TrackUploadProgressOptions = {},
): Promise<UploadResult> {
  const xhr = trackUploadProgress(options);
  const method = response.method ?? 'POST';

  return await new Promise<UploadResult>((resolve, reject) => {
    xhr.open(method, response.uploadUrl, true);

    Object.entries(response.headers ?? {}).forEach(([key, value]) => xhr.setRequestHeader(key, value));

    xhr.onload = () => {
      const { fileUrl, key } = parseUploadResponseMetadata(
        new Response(null, { status: xhr.status, statusText: xhr.statusText, headers: new Headers() }),
      );

      if (xhr.status >= 200 && xhr.status < 300) {
        resolve({ fileUrl: response.fileUrl ?? fileUrl, key: response.key ?? key, response: new Response(null, { status: xhr.status, statusText: xhr.statusText }) });
        return;
      }

      reject(new Error(`Upload failed with status ${xhr.status}`));
    };

    xhr.onerror = () => reject(new Error('Upload failed'));

    if (response.fields) {
      const form = new FormData();
      Object.entries(response.fields).forEach(([key, value]) => form.append(key, value));
      form.append('file', file);
      xhr.send(form);
      return;
    }

    xhr.send(file);
  });
}

export async function uploadFile(
  file: File | Blob,
  options: {
    request?: UploadRequestResponse;
    uploadUrl?: string;
    method?: 'PUT' | 'POST';
    headers?: Record<string, string>;
    fields?: Record<string, string>;
    onProgress?: UploadProgressHandler;
  } = {},
): Promise<UploadResult> {
  const request = options.request;
  const uploadUrl = options.uploadUrl ?? request?.uploadUrl;
  if (!uploadUrl) {
    throw new Error('Missing upload URL');
  }

  const method = options.method ?? request?.method ?? (request?.mode === 'presigned' ? 'PUT' : 'POST');
  const headers = { ...(request?.headers ?? {}), ...(options.headers ?? {}) };
  const fields = options.fields ?? (request && 'fields' in request ? request.fields : undefined);

  if (request?.mode === 'multipart' || fields) {
    return sendMultipartUpload(
      { ...(request ?? { mode: 'multipart', uploadUrl }), mode: 'multipart', uploadUrl, method, headers, fields },
      file,
      { onProgress: options.onProgress },
    );
  }

  const xhr = trackUploadProgress({ onProgress: options.onProgress });
  return await new Promise<UploadResult>((resolve, reject) => {
    xhr.open(method, uploadUrl, true);
    Object.entries(headers).forEach(([key, value]) => xhr.setRequestHeader(key, value));
    xhr.onload = () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        const { fileUrl, key } = parseUploadResponseMetadata(
          new Response(null, { status: xhr.status, statusText: xhr.statusText, headers: new Headers() }),
        );
        resolve({ fileUrl: request?.fileUrl ?? fileUrl, key: request?.key ?? key, response: new Response(null, { status: xhr.status, statusText: xhr.statusText }) });
        return;
      }
      reject(new Error(`Upload failed with status ${xhr.status}`));
    };
    xhr.onerror = () => reject(new Error('Upload failed'));
    xhr.send(file);
  });
}

