  const documentId = parseUuid(req.params.id);
  if (!documentId) return res.status(400).json({ error: 'Invalid document id' });

  const workspaceId = requireWorkspaceId(req);
  const document = await pool.query('SELECT id, workspace_id FROM documents WHERE id = $1', [documentId]);
  if (document.rowCount === 0 || document.rows[0]?.workspace_id !== workspaceId) return res.status(404).json({ error: 'Document not found' });

  const content = typeof req.body?.content === 'string' ? req.body.content.trim() : '';
  if (!content) return res.status(400).json({ error: 'content is required' });

  const parentId = req.body?.parent_id == null ? null : parseUuid(req.body.parent_id);
  if (req.body?.parent_id != null && !parentId) return res.status(400).json({ error: 'Invalid parent_id' });

  const requestedThreadId = req.body?.comment_id == null ? null : parseUuid(req.body.comment_id);
  if (req.body?.comment_id != null && !requestedThreadId) return res.status(400).json({ error: 'Invalid comment_id' });

  const authorId = requireUserId(req);

  if (parentId) {
    const parentResult = await pool.query<CommentWithWorkspaceRow>('SELECT c.*, d.workspace_id FROM comments c JOIN documents d ON d.id = c.document_id WHERE c.id = $1 AND c.deleted_at IS NULL', [parentId]);
    const parent = parentResult.rows[0];
    if (!parent || parent.document_id !== documentId || parent.workspace_id !== workspaceId) return res.status(404).json({ error: 'Parent comment not found' });
    if (requestedThreadId && parent.comment_id !== requestedThreadId) return res.status(400).json({ error: 'comment_id must match the parent thread' });
    const inserted = await pool.query<CommentRow>(
      'INSERT INTO comments (id, document_id, comment_id, parent_id, author_id, content) VALUES ($1, $2, $3, $4, $5, $6) RETURNING id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at',
      [randomUUID(), documentId, parent.comment_id, parentId, authorId, content]
    );
    return res.status(201).json({ comment: mapCommentRow(inserted.rows[0]!) });
