it('creates comment threads, replies, resolves, and persists resolved_at', async () => {
  const rootCreate = await request(app)
    .post(`/api/documents/${documentId}/comments`)
    .set('Cookie', authorCookie)
    .set('x-csrf-token', (await csrfTokenAndCookie(authorCookie)).csrfToken)
    .send({ content: 'Root thread' });

  expect(rootCreate.status).toBe(201);
  expect(rootCreate.body.comment).toMatchObject({
    parent_id: null,
    author_id: authorId,
    content: 'Root thread',
    resolved_at: null,
    resolved_by: null,
    deleted_at: null,
  });

  const replyRes = await request(app)
    .post(`/api/documents/${documentId}/comments`)
    .set('Cookie', otherCookie)
    .set('x-csrf-token', (await csrfTokenAndCookie(otherCookie)).csrfToken)
    .send({ content: 'Reply text', parent_id: rootCreate.body.comment.id });

  expect(replyRes.status).toBe(201);
  expect(replyRes.body.comment).toMatchObject({
    parent_id: rootCreate.body.comment.id,
    author_id: otherId,
    content: 'Reply text',
    resolved_at: null,
    resolved_by: null,
    deleted_at: null,
  });

  const listRes = await request(app).get(`/api/documents/${documentId}/comments`).set('Cookie', authorCookie);
  expect(listRes.status).toBe(200);
  expect(listRes.body.comments).toHaveLength(1);
  expect(listRes.body.comments[0]).toMatchObject({
    root: expect.objectContaining({
      id: rootCreate.body.comment.id,
      content: 'Root thread',
      resolved_at: null,
    }),
    replies: expect.arrayContaining([
      expect.objectContaining({ id: replyRes.body.comment.id, content: 'Reply text' }),
    ]),
  });

  const resolveAsOther = await request(app).post(`/api/comments/${rootCreate.body.comment.id}/resolve`).set('Cookie', otherCookie);
  expect(resolveAsOther.status).toBe(403);

  const resolveRes = await request(app).post(`/api/comments/${rootCreate.body.comment.id}/resolve`).set('Cookie', adminCookie);
  expect(resolveRes.status).toBe(200);
  expect(resolveRes.body).toMatchObject({
    id: rootCreate.body.comment.id,
    resolved_at: expect.any(String),
    resolved_by: adminId,
  });

  const resolvedRow = await pool.query('SELECT resolved_at, resolved_by FROM comments WHERE id = $1', [rootCreate.body.comment.id]);
  expect(resolvedRow.rows[0].resolved_at).toBeTruthy();
  expect(resolvedRow.rows[0].resolved_by).toBe(adminId);
});

